// ─── Feed Panel Content Types ──────────────────────────────────────
const FEED_TYPES = { auto: "Auto Embed", image: "Image", video_thumbnail: "Video Thumbnail", text_card: "Text Card", custom_embed: "Custom Embed" };

// ─── URL Profile Encoding ───────────────────────────────────────────
function encodeProfile(profile) {
  const data = {
    n: profile.name,
    h: profile.handle,
    b: profile.bio,
    t: profile.theme || "midnight",
    e: profile.email || "",
    p: profile.phone || "",
    s: {},
    cl: profile.customLinks || [],
    fp: profile.feedConfig || {},
  };
  Object.entries(profile.socials).forEach(([k, v]) => {
    if (v?.trim()) data.s[k] = v;
  });
  return btoa(encodeURIComponent(JSON.stringify(data)));
}

function decodeProfile(hash) {
  try {
    const data = JSON.parse(decodeURIComponent(atob(hash)));
    return {
      name: data.n || "",
      handle: data.h || "",
      bio: data.b || "",
      theme: data.t || "midnight",
      email: data.e || "",
      phone: data.p || "",
      socials: data.s || {},
      customLinks: data.cl || [],
      feedConfig: data.fp || {},
    };
  } catch {
    return null;
  }
}

// ─── vCard ──────────────────────────────────────────────────────────
function downloadVCard(profile) {
  const lines = ["BEGIN:VCARD", "VERSION:3.0", `FN:${profile.name || "LockedIn User"}`];
  if (profile.bio) lines.push(`NOTE:${profile.bio}`);
  if (profile.email) lines.push(`EMAIL:${profile.email}`);
  if (profile.phone) lines.push(`TEL:${profile.phone}`);
  Object.entries(profile.socials).forEach(([p, h]) => {
    if (!h?.trim()) return;
    const c = PLATFORMS[p];
    if (c) lines.push(`URL;type=${c.name}:${c.getProfileUrl(h)}`);
  });
  (profile.customLinks || []).forEach((cl) => {
    if (cl.url?.trim()) lines.push(`URL;type=${cl.label || "Link"}:${cl.url}`);
  });
  lines.push("END:VCARD");
  const blob = new Blob([lines.join("\r\n")], { type: "text/vcard;charset=utf-8" });
  const url = URL.createObjectURL(blob);
  const a = document.createElement("a");
  a.href = url;
  a.download = `${(profile.name || "contact").replace(/\s+/g, "_")}.vcf`;
  document.body.appendChild(a);
  a.click();
  document.body.removeChild(a);
  URL.revokeObjectURL(url);
}

function getAvatarUrl(profile) {
  if (profile.socials.github) return `https://github.com/${profile.socials.github}.png?size=200`;
  if (profile.socials.twitter) return `https://unavatar.io/twitter/${profile.socials.twitter}`;
  if (profile.socials.instagram) return `https://unavatar.io/instagram/${profile.socials.instagram}`;
  return null;
}

// ─── Feed Panel ─────────────────────────────────────────────────────
function FeedPanel({ platform, handle, isActive, onClick, theme, feedConfig }) {
  const config = PLATFORMS[platform];
  const t = THEMES[theme] || THEMES.midnight;
  if (!config || !handle) return null;

  const fc = feedConfig?.[platform] || {};
  const feedType = fc.feedType || "auto";
  const showInFeed = fc.showInFeed !== false;
  if (!showInFeed) return null;

  const renderEmbed = () => {
    // Custom feed type overrides
    if (feedType === "image" && fc.imageUrl) {
      return (
        <div style={{ display: "flex", flexDirection: "column", gap: 8 }}>
          <img src={fc.imageUrl} alt={fc.caption || config.name} style={{ width: "100%", borderRadius: 8, maxHeight: 300, objectFit: "cover" }} />
          {fc.caption && <p style={{ fontSize: 12, color: t.sub, textAlign: "center" }}>{fc.caption}</p>}
        </div>
      );
    }
    if (feedType === "video_thumbnail" && fc.videoUrl) {
      // Auto-extract YouTube thumbnail from video URL
      let thumbUrl = fc.thumbnailUrl;
      if (!thumbUrl) {
        const ytMatch = fc.videoUrl.match(/(?:youtube\.com\/watch\?v=|youtu\.be\/|youtube\.com\/embed\/)([a-zA-Z0-9_-]{11})/);
        if (ytMatch) thumbUrl = `https://img.youtube.com/vi/${ytMatch[1]}/hqdefault.jpg`;
      }
      // If it's a YouTube URL, embed the video directly instead of just a thumbnail
      const ytId = fc.videoUrl.match(/(?:youtube\.com\/watch\?v=|youtu\.be\/|youtube\.com\/embed\/)([a-zA-Z0-9_-]{11})/);
      if (ytId) {
        return (
          <div style={{ display: "flex", flexDirection: "column", gap: 8 }}>
            <div style={{ width: "100%", height: 280, borderRadius: 8, overflow: "hidden" }}>
              <iframe src={`https://www.youtube.com/embed/${ytId[1]}`} style={{ width: "100%", height: "100%", border: "none", borderRadius: 8 }} allow="accelerometer; autoplay; clipboard-write; encrypted-media; gyroscope; picture-in-picture" allowFullScreen title="YouTube Video" />
            </div>
            {fc.caption && <p style={{ fontSize: 12, color: t.sub, textAlign: "center", fontWeight: 600 }}>{fc.caption}</p>}
          </div>
        );
      }
      return (
        <a href={fc.videoUrl} target="_blank" rel="noopener noreferrer" style={{ display: "block", position: "relative" }}>
          <img src={thumbUrl || fc.videoUrl} alt="Video" style={{ width: "100%", borderRadius: 8, maxHeight: 300, objectFit: "cover" }} />
          <div style={{ position: "absolute", inset: 0, display: "flex", alignItems: "center", justifyContent: "center" }}>
            <div style={{ width: 56, height: 56, borderRadius: "50%", background: "rgba(0,0,0,0.75)", display: "flex", alignItems: "center", justifyContent: "center", boxShadow: "0 4px 20px rgba(0,0,0,0.5)" }}>
              <svg width="22" height="22" viewBox="0 0 24 24" fill="#fff"><path d="M8 5v14l11-7z" /></svg>
            </div>
          </div>
          {fc.caption && <p style={{ fontSize: 12, color: t.sub, textAlign: "center", marginTop: 8, fontWeight: 600 }}>{fc.caption}</p>}
        </a>
      );
    }
    if (feedType === "text_card" && fc.textContent) {
      return (
        <div style={{ padding: "16px 12px", background: `${config.color}08`, borderRadius: 8, border: `1px solid ${config.color}15` }}>
          <p style={{ fontSize: 14, color: t.text, lineHeight: 1.6, whiteSpace: "pre-wrap" }}>{fc.textContent}</p>
        </div>
      );
    }
    if (feedType === "custom_embed" && fc.embedUrl) {
      return <div style={{ width: "100%", height: 300, borderRadius: 8, overflow: "hidden" }}><iframe src={fc.embedUrl} style={{ width: "100%", height: "100%", border: "none", borderRadius: 8 }} title="Custom Embed" /></div>;
    }

    // Default auto embeds
    switch (platform) {
      case "twitter":
        return <div style={{ width: "100%", minHeight: 300, borderRadius: 8, overflow: "hidden", background: "rgba(0,0,0,0.3)" }}><a className="twitter-timeline" data-theme="dark" data-chrome="noheader nofooter transparent" data-tweet-limit="5" href={`https://twitter.com/${handle}`}>Loading...</a></div>;
      case "youtube": {
        // If handle looks like a video ID (11 chars, no @ or /), embed that video directly
        const isVideoId = /^[a-zA-Z0-9_-]{11}$/.test(handle);
        const embedUrl = isVideoId
          ? `https://www.youtube.com/embed/${handle}`
          : `https://www.youtube.com/embed?listType=user_uploads&list=${handle.replace(/^@/, "")}`;
        return <div style={{ width: "100%", height: 300, borderRadius: 8, overflow: "hidden" }}><iframe src={embedUrl} style={{ width: "100%", height: "100%", border: "none", borderRadius: 8 }} allow="accelerometer; autoplay; clipboard-write; encrypted-media; gyroscope; picture-in-picture" allowFullScreen title="YouTube" /></div>;
      }
      case "github":
        return <div style={{ display: "flex", flexDirection: "column", alignItems: "center", gap: 10 }}>
          <img src={`https://ghchart.rshah.org/${t.accent.replace("#", "")}/${handle}`} alt="contributions" style={{ width: "100%", borderRadius: 8 }} />
          <a href={config.getProfileUrl(handle)} target="_blank" rel="noopener noreferrer" style={{ padding: "8px 16px", background: `${t.accent}15`, border: `1px solid ${t.accent}30`, borderRadius: 8, color: t.accent, fontSize: 12, fontWeight: 600, textDecoration: "none", fontFamily: "'Outfit', sans-serif" }}>View @{handle}</a>
        </div>;
      case "spotify":
        return <div style={{ width: "100%", height: 300, borderRadius: 8, overflow: "hidden" }}><iframe src={`https://open.spotify.com/embed/artist/${handle}?theme=0`} style={{ width: "100%", height: "100%", border: "none", borderRadius: 8 }} title="Spotify" /></div>;
      case "twitch":
        return <div style={{ width: "100%", height: 300, borderRadius: 8, overflow: "hidden" }}><iframe src={`https://player.twitch.tv/?channel=${handle}&parent=${window.location.hostname}&muted=true`} style={{ width: "100%", height: "100%", border: "none", borderRadius: 8 }} title="Twitch" /></div>;
      default:
        return <div style={{ display: "flex", alignItems: "center", gap: 12, padding: "20px 0" }}>
          <div style={{ width: 48, height: 48, borderRadius: 12, background: `${config.color}15`, display: "flex", alignItems: "center", justifyContent: "center", color: config.color }}>{config.icon}</div>
          <div><span style={{ color: t.text, fontSize: 14, fontWeight: 600 }}>{config.name}</span><br /><span style={{ color: t.sub, fontSize: 12 }}>{platform === "website" ? handle : `@${handle.replace(/^@/, "")}`}</span></div>
          <a href={config.getProfileUrl(handle)} target="_blank" rel="noopener noreferrer" style={{ marginLeft: "auto", padding: "6px 14px", background: `${config.color}15`, border: `1px solid ${config.color}25`, borderRadius: 8, color: config.color, fontSize: 11, fontWeight: 600, textDecoration: "none", fontFamily: "'Outfit', sans-serif" }}>Visit</a>
        </div>;
    }
  };

  return (
    <div className="feed-panel" onClick={onClick} style={{ background: isActive ? `${config.color}08` : `${t.cardBg}`, border: `1px solid ${isActive ? config.color + "40" : t.border}`, borderRadius: 16, overflow: "hidden", marginBottom: 12, cursor: "pointer", transition: "all 0.3s", boxShadow: isActive ? `0 0 30px ${config.color}10` : "none" }}>
      <div style={{ display: "flex", alignItems: "center", gap: 8, padding: "10px 14px", borderBottom: `1px solid ${t.border}` }}>
        <div style={{ width: 6, height: 6, borderRadius: "50%", background: config.color }} />
        <div style={{ display: "flex", alignItems: "center", gap: 6, color: config.color }}>{config.icon}<span style={{ fontWeight: 700, fontSize: 12, letterSpacing: 0.5 }}>{config.name}</span></div>
        <span style={{ marginLeft: "auto", fontSize: 11, color: t.sub, fontFamily: "'Space Mono', monospace" }}>{platform === "website" ? handle : `@${handle.replace(/^@/, "")}`}</span>
      </div>
      <div style={{ padding: 12 }}>{renderEmbed()}</div>
    </div>
  );
}

